fn entry(kind: SemaDiagKind) -> &'static CatalogEntry {
    ENTRIES
        .iter()
        .find(|entry| entry.kind == kind)
        .expect("missing generated diagnostic catalog entry")
}

pub fn code(kind: SemaDiagKind) -> u16 {
    entry(kind).code
}

pub fn message(kind: SemaDiagKind) -> &'static str {
    entry(kind).message
}

pub fn primary(kind: SemaDiagKind) -> &'static str {
    entry(kind).primary
}

pub fn render_message(kind: SemaDiagKind, context: &DiagContext) -> String {
    context.render(entry(kind).message)
}

pub fn render_primary(kind: SemaDiagKind, context: &DiagContext) -> String {
    context.render(entry(kind).primary)
}

pub fn secondary(kind: SemaDiagKind) -> Option<&'static str> {
    entry(kind).secondary
}

pub fn render_secondary(kind: SemaDiagKind, context: &DiagContext) -> Option<String> {
    entry(kind)
        .secondary
        .map(|secondary| context.render(secondary))
}

pub fn help(kind: SemaDiagKind) -> Option<&'static str> {
    entry(kind).help
}

pub fn from_code(raw: u16) -> Option<SemaDiagKind> {
    ENTRIES
        .iter()
        .find(|entry| entry.code == raw)
        .map(|entry| entry.kind)
}
